  /** Scan to get the next Symbol. */
  public java_cup.runtime.Symbol scan()
    throws java.lang.Exception
    {

    Symbol token = lex.next_token();

    if (token != null) {
        if (token.left >= 0) lastLine = token.left + 1;
        if (token.right >= 0) lastColumn = token.right + 1;
    }

    return token;

    }


    /*
     * Referencia al analizador léxico.
     * A través de este objeto el parser obtiene los tokens.
     */
    Lexer lex;

    /*
     * Tabla donde se almacenan funciones, parámetros, variables
     * y arreglos encontrados durante el análisis.
     */
    TablaSimbolos tabla;

    /*
     * Manejador encargado de registrar los errores sintácticos.
     * Se obtiene desde el lexer para centralizar los errores léxicos
     * y sintácticos en un mismo archivo.
     */
    ManejadorErrores manejadorErrores;

    /*
     * Contadores utilizados para generar nombres únicos de scopes,
     * por ejemplo if1_main, switch1_main, dowhile1_main, etc.
     */
    HashMap<String, Integer> contadores = new HashMap<>();

    /*
     * Última línea y columna leída. Se usan como respaldo cuando
     * ocurre un error y el token no trae una posición clara.
     */
    private int lastLine = 1;
    private int lastColumn = 1;

    /*
     * Tipo del arreglo actual siendo inicializado.
     * Se usa para validar que los valores iniciales tengan el tipo correcto.
     */
    private String tipoArregloActual = null;

    private boolean returnEnBloque = false; // Indica si ya se ha encontrado un return en el bloque actual

    /*
     * Constructor del parser.
     * Recibe el lexer, crea la tabla de símbolos y obtiene el
     * manejador de errores para poder reportar errores sintácticos.
     */
    public parser(Lexer lex) {
        this.lex = lex;
        this.tabla = new TablaSimbolos();
        this.manejadorErrores = lex.getManejadorErrores();
    }

    /*
     * Permite acceder a la tabla de símbolos desde el Main.
     * Esto es útil para escribir la tabla al finalizar el análisis.
     */
    public TablaSimbolos getTabla() {
        return tabla;
    }

    /*
     * Genera un nombre único para cada scope interno.
     * Se utiliza principalmente en if, else, do-while y switch.
     */
    private String nuevoScope(String tipo) {
        String key = tipo + "_" + tabla.getCurrentScope();
        int count = contadores.getOrDefault(key, 0) + 1;
        contadores.put(key, count);
        return tipo + count + "_" + tabla.getCurrentScope();
    }

    /*
     * Método llamado automáticamente por CUP cuando detecta
     * un error sintáctico. Aquí se construye un mensaje claro
     * y se envía al manejador de errores.
     */
    public void syntax_error(Symbol token) {
        String msj;

        if (token == null || token.sym == sym.EOF) {
            msj = "Fin de archivo inesperado";
        } else if (token.value != null) {
            msj = "Token inesperado: " + token.value;
        } else {
            msj = "Token inesperado: " + sym.terminalNames[token.sym];
        }

        if (manejadorErrores != null) {
            manejadorErrores.agregarErrorSintactico(
                msj,
                (token != null ? token.left : lastLine - 1),
                (token != null ? token.right : lastColumn - 1)
            );
        } else {
            System.err.println("Error Sintáctico: " + msj);
        }
    }

    /*
     * Método llamado cuando CUP no logra recuperarse del error.
     * Se deja como último recurso 
     */
    public void unrecovered_syntax_error(Symbol token) throws Exception {
        if (token == null || token.sym == sym.EOF) {
            return;
        }

        String msj = "Error sintáctico no recuperable: token inesperado";

        if (manejadorErrores != null) {
            manejadorErrores.agregarErrorSintactico(
                msj,
                token.left,
                token.right
            );
        }
    }

    private String crearExpr(String valor, String tipo) {
        return valor + ":" + tipo;
    }

    private String getValorExpr(String expr) {
        if (expr == null || !expr.contains(":")) {
            return "";
        }

        return expr.substring(0, expr.lastIndexOf(":"));
    }

    private String getTipoExpr(String expr) {
        if (expr == null || !expr.contains(":")) {
            return "error";
        }

        return expr.substring(expr.lastIndexOf(":") + 1);
    }

